import { and, eq } from "drizzle-orm";
import type { Db } from "@ironworksai/db";
import { agents } from "@ironworksai/db";
import { createAgentDocument } from "./agent-workspace.js";
import { logger } from "../middleware/logger.js";

type EmploymentEventType = "hired" | "department_change" | "performance_review" | "promotion" | "terminated";

// ── HR Personnel File Management ────────────────────────────────────────────
//
// Creates auto-generated knowledge pages for personnel records.
// If a VP of HR agent exists in the company, documents are scoped to that
// agent's workspace. Otherwise they are created with agent_id = null.

function slugifyName(name: string): string {
  return name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    || "agent";
}

function formatDate(date: Date): string {
  return date.toISOString().slice(0, 10);
}

/**
 * Find the VP of HR agent for a company, if one exists.
 */
async function findHrAgent(db: Db, companyId: string): Promise<string | null> {
  const [hr] = await db
    .select({ id: agents.id })
    .from(agents)
    .where(
      and(
        eq(agents.companyId, companyId),
        eq(agents.role, "vp_hr"),
      ),
    )
    .limit(1);

  if (hr) return hr.id;

  // Also check for common role name variations
  const rows = await db
    .select({ id: agents.id, role: agents.role })
    .from(agents)
    .where(eq(agents.companyId, companyId));

  for (const row of rows) {
    const r = row.role.toLowerCase();
    if (
      (r.includes("hr") && (r.includes("vp") || r.includes("vice") || r.includes("head"))) ||
      r === "hr_director"
    ) {
      return row.id;
    }
  }

  return null;
}

/**
 * Create a hiring record when a new agent is hired.
 */
export async function createHiringRecord(
  db: Db,
  opts: {
    companyId: string;
    hrAgentId: string | null;
    hiredAgentId: string;
    hiredAgentName: string;
    hiredAgentRole: string;
    employmentType: string;
    hiredByUserId: string | null;
    hiredByAgentId: string | null;
  },
): Promise<void> {
  const {
    companyId,
    hiredAgentId,
    hiredAgentName,
    hiredAgentRole,
    employmentType,
    hiredByUserId,
    hiredByAgentId,
  } = opts;

  // Resolve HR agent if not provided
  const hrAgentId = opts.hrAgentId ?? await findHrAgent(db, companyId);

  const nameSlug = slugifyName(hiredAgentName);
  const date = formatDate(new Date());
  const slug = `hr-personnel-${nameSlug}-hiring-${date}`;

  const hiredBy = hiredByUserId
    ? `Board User (${hiredByUserId})`
    : hiredByAgentId
      ? `Agent (${hiredByAgentId})`
      : "System";

  const content = [
    `# Hiring Record - ${hiredAgentName}`,
    "",
    "## Agent Information",
    `- **Name:** ${hiredAgentName}`,
    `- **Role:** ${hiredAgentRole}`,
    `- **Employment Type:** ${employmentType}`,
    `- **Hired Date:** ${date}`,
    `- **Hired By:** ${hiredBy}`,
    "",
    "## Status",
    "- **Current Status:** idle (newly hired)",
    "",
    "## Notes",
    "",
    "[VP of HR adds onboarding notes here]",
  ].join("\n");

  await createAgentDocument(db, {
    agentId: hrAgentId ?? hiredAgentId,
    companyId,
    title: `Hiring Record - ${hiredAgentName}`,
    content,
    documentType: "personnel",
    slug,
    department: "hr",
    visibility: hrAgentId ? "private" : "company",
    autoGenerated: true,
    createdByUserId: "system",
  });

  logger.info(
    { companyId, hiredAgentId, hiredAgentName, hrAgentId },
    "hiring record created",
  );
}

