/**
 * Create a performance review document for an agent.
 */
export async function createPerformanceReview(
  db: Db,
  opts: {
    companyId: string;
    hrAgentId: string | null;
    reviewedAgentId: string;
    reviewedAgentName: string;
    performanceScore: number;
    summary: string;
  },
): Promise<void> {
  const {
    companyId,
    reviewedAgentId,
    reviewedAgentName,
    performanceScore,
    summary,
  } = opts;

  const hrAgentId = opts.hrAgentId ?? await findHrAgent(db, companyId);

  const nameSlug = slugifyName(reviewedAgentName);
  const date = formatDate(new Date());
  const slug = `hr-personnel-${nameSlug}-review-${date}`;

  // Derive letter grade from score
  let grade = "F";
  if (performanceScore >= 90) grade = "A";
  else if (performanceScore >= 80) grade = "B";
  else if (performanceScore >= 70) grade = "C";
  else if (performanceScore >= 60) grade = "D";

  const content = [
    `# Performance Review - ${reviewedAgentName} - ${date}`,
    "",
    "## Metrics",
    `- **Performance Score:** ${performanceScore} (${grade} rating)`,
    "",
    "## Summary",
    summary,
    "",
    "## Strengths",
    "",
    "[To be filled by VP of HR]",
    "",
    "## Areas for Improvement",
    "",
    "[To be filled by VP of HR]",
    "",
    "## Recommendation",
    "",
    "[continue / promote / PIP / terminate]",
  ].join("\n");

  await createAgentDocument(db, {
    agentId: hrAgentId ?? reviewedAgentId,
    companyId,
    title: `Performance Review - ${reviewedAgentName} - ${date}`,
    content,
    documentType: "review",
    slug,
    department: "hr",
    visibility: hrAgentId ? "private" : "company",
    autoGenerated: true,
    createdByUserId: "system",
  });

  logger.info(
    { companyId, reviewedAgentId, reviewedAgentName, performanceScore, hrAgentId },
    "performance review created",
  );
}

/**
 * Create an employment history entry for tracking significant agent lifecycle events.
 *
 * Creates a knowledge page in the HR personnel folder with document_type
 * "employment_history". These entries build a chronological record of
 * each agent's career events.
 */
export async function createEmploymentHistoryEntry(
  db: Db,
  opts: {
    companyId: string;
    agentId: string;
    agentName: string;
    eventType: EmploymentEventType;
    details: string;
  },
): Promise<void> {
  const { companyId, agentId, agentName, eventType, details } = opts;

  const hrAgentId = await findHrAgent(db, companyId);
  const nameSlug = slugifyName(agentName);
  const date = formatDate(new Date());
  const slug = `hr-employment-history-${nameSlug}-${eventType}-${date}`;

  const eventLabel: Record<EmploymentEventType, string> = {
    hired: "Hiring",
    department_change: "Department Change",
    performance_review: "Performance Review",
    promotion: "Promotion",
    terminated: "Termination",
  };

  const content = [
    `# Employment History - ${agentName} - ${eventLabel[eventType]}`,
    "",
    "## Event Details",
    `- **Agent:** ${agentName}`,
    `- **Event Type:** ${eventLabel[eventType]}`,
    `- **Date:** ${date}`,
    "",
    "## Details",
    details,
    "",
    "## Notes",
    "",
    "[VP of HR adds notes here]",
  ].join("\n");

  await createAgentDocument(db, {
    agentId: hrAgentId ?? agentId,
    companyId,
    title: `Employment History - ${agentName} - ${eventLabel[eventType]} - ${date}`,
    content,
    documentType: "employment_history",
    slug,
    department: "hr",
    visibility: hrAgentId ? "private" : "company",
    autoGenerated: true,
    createdByUserId: "system",
  });

  logger.info(
    { companyId, agentId, agentName, eventType, hrAgentId },
    "employment history entry created",
  );
}
